27	export async function createPostRecord(input: { title: string; content: string }) {
28	  const post: Post = {
29	    id: nextPostId,
30	    title: input.title,
31	    content: input.content,
32	    createdAt: new Date().toISOString()
33	  };
34	
35	  nextPostId += 1;
36	  posts.unshift(post);
37	
38	  return post;
